3	const isNeighbor = (a: Cell, b: Cell): boolean =>
4	  Math.abs(a.x - b.x) <= 1 &&
5	  Math.abs(a.y - b.y) <= 1 &&
6	  (a.x !== b.x || a.y !== b.y);
7	
8	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
9	  liveCells.filter((candidate) => isNeighbor(cell, candidate)).length;
10	
11	const getCandidateDeadCells = (liveCells: Cell[]): Cell[] => {
12	  const candidates: Cell[] = [];
13	  for (const cell of liveCells) {
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const candidate = { x: cell.x + dx, y: cell.y + dy };
18	        const isAlive = liveCells.some((c) => c.x === candidate.x && c.y === candidate.y);
19	        const alreadyAdded = candidates.some((c) => c.x === candidate.x && c.y === candidate.y);
20	        if (!isAlive && !alreadyAdded) candidates.push(candidate);
21	      }
22	    }
23	  }
24	  return candidates;
25	};
26	
27	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
28	  const survivors = liveCells.filter((cell) => {
29	    const neighbors = countNeighbors(cell, liveCells);
30	    return neighbors === 2 || neighbors === 3;
31	  });
32	
33	  const newborns = getCandidateDeadCells(liveCells).filter(
34	    (cell) => countNeighbors(cell, liveCells) === 3
35	  );
36	
37	  return [...survivors, ...newborns];
38	};
