**`getCandidateDeadCells` (lines 11-25):**
```
const getCandidateDeadCells = (liveCells: Cell[]): Cell[] => {
  const candidates: Cell[] = [];
  for (const cell of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate = { x: cell.x + dx, y: cell.y + dy };
        const isAlive = liveCells.some((c) => c.x === candidate.x && c.y === candidate.y);
        const alreadyAdded = candidates.some((c) => c.x === candidate.x && c.y === candidate.y);
        if (!isAlive && !alreadyAdded) candidates.push(candidate);
